namespace VetClinic.Data;

public class Pet
{
    public int Id { get; set; }
    public string Name { get; set; } = "";
    public string Species { get; set; } = "";
    public string Breed { get; set; } = "";
    public DateTime DateOfBirth { get; set; }
    public string OwnerName { get; set; } = "";
    public string OwnerPhone { get; set; } = "";
    public string OwnerEmail { get; set; } = "";
    public DateTime RegisteredDate { get; set; } = DateTime.UtcNow;
    public List<MedicalRecord> MedicalRecords { get; set; } = new();
    public List<Appointment> Appointments { get; set; } = new();
    public List<Invoice> Invoices { get; set; } = new();
}

public class MedicalRecord
{
    public int Id { get; set; }
    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;
    public DateTime Date { get; set; } = DateTime.UtcNow;
    public string Diagnosis { get; set; } = "";
    public string Treatment { get; set; } = "";
    public string Notes { get; set; } = "";
    public string VetName { get; set; } = "";
}

public class Appointment
{
    public int Id { get; set; }
    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;
    public DateTime ScheduledDate { get; set; }
    public TimeSpan Duration { get; set; } = TimeSpan.FromMinutes(30);
    public string Reason { get; set; } = "";
    public string VetName { get; set; } = "";
    public AppointmentStatus Status { get; set; } = AppointmentStatus.Scheduled;
    public string Notes { get; set; } = "";
}

public enum AppointmentStatus
{
    Scheduled,
    Completed,
    Cancelled,
    NoShow
}

public class Invoice
{
    public int Id { get; set; }
    public int PetId { get; set; }
    public Pet Pet { get; set; } = null!;
    public DateTime IssuedDate { get; set; } = DateTime.UtcNow;
    public DateTime? PaidDate { get; set; }
    public List<InvoiceItem> Items { get; set; } = new();
    public decimal TotalAmount => Items.Sum(i => i.Amount);
    public InvoiceStatus Status { get; set; } = InvoiceStatus.Unpaid;
    public string Notes { get; set; } = "";
}

public enum InvoiceStatus
{
    Unpaid,
    Paid,
    Overdue,
    Cancelled
}

public class InvoiceItem
{
    public int Id { get; set; }
    public int InvoiceId { get; set; }
    public Invoice Invoice { get; set; } = null!;
    public string Description { get; set; } = "";
    public decimal Amount { get; set; }
}

using Microsoft.EntityFrameworkCore;

namespace VetClinic.Data;

public class ClinicService(ApplicationDbContext db)
{
    // Pets
    public async Task<List<Pet>> GetAllPetsAsync()
        => await db.Pets.OrderBy(p => p.Name).ToListAsync();

    public async Task<Pet?> GetPetByIdAsync(int id)
        => await db.Pets.Include(p => p.MedicalRecords.OrderByDescending(m => m.Date))
                        .Include(p => p.Appointments.OrderByDescending(a => a.ScheduledDate))
                        .Include(p => p.Invoices).ThenInclude(i => i.Items)
                        .FirstOrDefaultAsync(p => p.Id == id);

    public async Task<Pet> CreatePetAsync(Pet pet)
    {
        db.Pets.Add(pet);
        await db.SaveChangesAsync();
        return pet;
    }

    public async Task UpdatePetAsync(Pet pet)
    {
        db.Pets.Update(pet);
        await db.SaveChangesAsync();
    }

    public async Task DeletePetAsync(int id)
    {
        var pet = await db.Pets.FindAsync(id);
        if (pet != null)
        {
            db.Pets.Remove(pet);
            await db.SaveChangesAsync();
        }
    }

    // Medical Records
    public async Task<List<MedicalRecord>> GetMedicalRecordsByPetIdAsync(int petId)
        => await db.MedicalRecords.Where(m => m.PetId == petId).OrderByDescending(m => m.Date).ToListAsync();

    public async Task<MedicalRecord> CreateMedicalRecordAsync(MedicalRecord record)
    {
        db.MedicalRecords.Add(record);
        await db.SaveChangesAsync();
        return record;
    }

    // Appointments
    public async Task<List<Appointment>> GetAllAppointmentsAsync()
        => await db.Appointments.Include(a => a.Pet).OrderByDescending(a => a.ScheduledDate).ToListAsync();

    public async Task<List<Appointment>> GetAppointmentsByDateAsync(DateTime date)
        => await db.Appointments.Include(a => a.Pet)
                   .Where(a => a.ScheduledDate.Date == date.Date)
                   .OrderBy(a => a.ScheduledDate)
                   .ToListAsync();

    public async Task<List<Appointment>> GetAppointmentsByPetIdAsync(int petId)
        => await db.Appointments.Where(a => a.PetId == petId).OrderByDescending(a => a.ScheduledDate).ToListAsync();

    public async Task<Appointment> CreateAppointmentAsync(Appointment appointment)
    {
        db.Appointments.Add(appointment);
        await db.SaveChangesAsync();
        return appointment;
    }

    public async Task UpdateAppointmentAsync(Appointment appointment)
    {
        db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public async Task CancelAppointmentAsync(int id)
    {
        var appointment = await db.Appointments.FindAsync(id);
        if (appointment != null)
        {
            appointment.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }

    public async Task<List<DateTime>> GetAvailableSlotsAsync(DateTime date)
    {
        var bookedSlots = await db.Appointments
            .Where(a => a.ScheduledDate.Date == date.Date && a.Status == AppointmentStatus.Scheduled)
            .Select(a => a.ScheduledDate)
            .ToListAsync();

        var slots = new List<DateTime>();
        var start = date.Date.AddHours(9);
        var end = date.Date.AddHours(17);

        for (var time = start; time < end; time = time.AddMinutes(30))
        {
            if (!bookedSlots.Any(b => b == time))
            {
                slots.Add(time);
            }
        }

        return slots;
    }

    // Invoices
    public async Task<List<Invoice>> GetAllInvoicesAsync()
        => await db.Invoices.Include(i => i.Pet).Include(i => i.Items).OrderByDescending(i => i.IssuedDate).ToListAsync();

    public async Task<List<Invoice>> GetInvoicesByPetIdAsync(int petId)
        => await db.Invoices.Include(i => i.Items).Where(i => i.PetId == petId).OrderByDescending(i => i.IssuedDate).ToListAsync();

    public async Task<Invoice?> GetInvoiceByIdAsync(int id)
        => await db.Invoices.Include(i => i.Pet).Include(i => i.Items).FirstOrDefaultAsync(i => i.Id == id);

    public async Task<Invoice> CreateInvoiceAsync(Invoice invoice)
    {
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task AddInvoiceItemAsync(InvoiceItem item)
    {
        db.InvoiceItems.Add(item);
        await db.SaveChangesAsync();
    }

    public async Task MarkInvoicePaidAsync(int id)
    {
        var invoice = await db.Invoices.FindAsync(id);
        if (invoice != null)
        {
            invoice.Status = InvoiceStatus.Paid;
            invoice.PaidDate = DateTime.UtcNow;
            await db.SaveChangesAsync();
        }
    }

    // Dashboard
    public async Task<int> GetTotalPetsCountAsync()
        => await db.Pets.CountAsync();

    public async Task<int> GetTodayAppointmentsCountAsync()
        => await db.Appointments.CountAsync(a => a.ScheduledDate.Date == DateTime.Today && a.Status == AppointmentStatus.Scheduled);

    public async Task<int> GetUnpaidInvoicesCountAsync()
        => await db.Invoices.CountAsync(i => i.Status == InvoiceStatus.Unpaid);
}

