@page "/patients"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data
@attribute [Authorize]
@inject ClinicService ClinicService
@inject NavigationManager Nav

<PageTitle>Patients - VetClinic</PageTitle>

<h1 class="mb-4">Patients</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by name, owner, or species..." @bind="searchTerm" @bind:event="oninput" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick="ToggleForm">
            @(showForm ? "Cancel" : "Register New Pet")
        </button>
    </div>
</div>

@if (showForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Register New Pet</h5>
            <EditForm Model="newPet" OnValidSubmit="CreatePet" FormName="newPetForm">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Name</label>
                        <InputText class="form-control" @bind-Value="newPet.Name" />
                    </div>
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Species</label>
                        <InputText class="form-control" @bind-Value="newPet.Species" />
                    </div>
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Breed</label>
                        <InputText class="form-control" @bind-Value="newPet.Breed" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Date of Birth</label>
                        <InputDate class="form-control" @bind-Value="newPet.DateOfBirth" />
                    </div>
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Owner Name</label>
                        <InputText class="form-control" @bind-Value="newPet.OwnerName" />
                    </div>
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Owner Phone</label>
                        <InputText class="form-control" @bind-Value="newPet.OwnerPhone" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-4 mb-3">
                        <label class="form-label">Owner Email</label>
                        <InputText class="form-control" @bind-Value="newPet.OwnerEmail" />
                    </div>
                </div>
                <button type="submit" class="btn btn-success">Register</button>
            </EditForm>
        </div>
    </div>
}

@if (pets == null)
{
    <p>Loading...</p>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Name</th>
                <th>Species</th>
                <th>Breed</th>
                <th>Owner</th>
                <th>Registered</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var pet in FilteredPets)
            {
                <tr style="cursor:pointer" @onclick="() => Nav.NavigateTo($&quot;/patients/{pet.Id}&quot;)">
                    <td>@pet.Name</td>
                    <td>@pet.Species</td>
                    <td>@pet.Breed</td>
                    <td>@pet.OwnerName</td>
                    <td>@pet.RegisteredDate.ToShortDateString()</td>
                </tr>
            }
        </tbody>
    </table>

    @if (!FilteredPets.Any())
    {
        <p class="text-muted">No patients found.</p>
    }
}

@code {
    private List<Pet>? pets;
    private string searchTerm = "";
    private bool showForm;
    private Pet newPet = new() { DateOfBirth = DateTime.Today };

    private IEnumerable<Pet> FilteredPets => pets?.Where(p =>
        string.IsNullOrEmpty(searchTerm) ||
        p.Name.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
        p.OwnerName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
        p.Species.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
    ) ?? Enumerable.Empty<Pet>();

    protected override async Task OnInitializedAsync()
    {
        pets = await ClinicService.GetAllPetsAsync();
    }

    private void ToggleForm() => showForm = !showForm;

    private async Task CreatePet()
    {
        newPet.RegisteredDate = DateTime.UtcNow;
        await ClinicService.CreatePetAsync(newPet);
        newPet = new() { DateOfBirth = DateTime.Today };
        showForm = false;
        pets = await ClinicService.GetAllPetsAsync();
    }
}

@page "/patients/{Id:int}"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data
@attribute [Authorize]
@inject ClinicService ClinicService
@inject NavigationManager Nav

<PageTitle>Patient Detail - VetClinic</PageTitle>

@if (pet == null)
{
    <p>Loading...</p>
}
else
{
    <h1 class="mb-4">@pet.Name</h1>

    <ul class="nav nav-tabs mb-3">
        <li class="nav-item">
            <button class="nav-link @(activeTab == "info" ? "active" : "")" @onclick='() => activeTab = "info"'>Info</button>
        </li>
        <li class="nav-item">
            <button class="nav-link @(activeTab == "medical" ? "active" : "")" @onclick='() => activeTab = "medical"'>Medical History</button>
        </li>
        <li class="nav-item">
            <button class="nav-link @(activeTab == "appointments" ? "active" : "")" @onclick='() => activeTab = "appointments"'>Appointments</button>
        </li>
        <li class="nav-item">
            <button class="nav-link @(activeTab == "invoices" ? "active" : "")" @onclick='() => activeTab = "invoices"'>Invoices</button>
        </li>
    </ul>

    @if (activeTab == "info")
    {
        <div class="card">
            <div class="card-body">
                <EditForm Model="pet" OnValidSubmit="UpdatePet" FormName="editPetForm">
                    <DataAnnotationsValidator />
                    <div class="row">
                        <div class="col-md-4 mb-3">
                            <label class="form-label">Name</label>
                            <InputText class="form-control" @bind-Value="pet.Name" />
                        </div>
                        <div class="col-md-4 mb-3">
                            <label class="form-label">Species</label>
                            <InputText class="form-control" @bind-Value="pet.Species" />
                        </div>
                        <div class="col-md-4 mb-3">
                            <label class="form-label">Breed</label>
                            <InputText class="form-control" @bind-Value="pet.Breed" />
                        </div>
                    </div>
                    <div class="row">
                        <div class="col-md-4 mb-3">
                            <label class="form-label">Date of Birth</label>
                            <InputDate class="form-control" @bind-Value="pet.DateOfBirth" />
                        </div>
                        <div class="col-md-4 mb-3">
                            <label class="form-label">Owner Name</label>
                            <InputText class="form-control" @bind-Value="pet.OwnerName" />
                        </div>
                        <div class="col-md-4 mb-3">
                            <label class="form-label">Owner Phone</label>
                            <InputText class="form-control" @bind-Value="pet.OwnerPhone" />
                        </div>
                    </div>
                    <div class="row">
                        <div class="col-md-4 mb-3">
                            <label class="form-label">Owner Email</label>
                            <InputText class="form-control" @bind-Value="pet.OwnerEmail" />
                        </div>
                    </div>
                    <button type="submit" class="btn btn-primary">Save Changes</button>
                    <button type="button" class="btn btn-danger ms-2" @onclick="DeletePet">Delete Patient</button>
                </EditForm>
            </div>
        </div>
    }

    @if (activeTab == "medical")
    {
        <button class="btn btn-primary mb-3" @onclick="ToggleMedicalForm">
            @(showMedicalForm ? "Cancel" : "Add Record")
        </button>

        @if (showMedicalForm)
        {
            <div class="card mb-3">
                <div class="card-body">
                    <EditForm Model="newRecord" OnValidSubmit="CreateMedicalRecord" FormName="newRecordForm">
                        <DataAnnotationsValidator />
                        <div class="row">
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Diagnosis</label>
                                <InputText class="form-control" @bind-Value="newRecord.Diagnosis" />
                            </div>
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Treatment</label>
                                <InputText class="form-control" @bind-Value="newRecord.Treatment" />
                            </div>
                        </div>
                        <div class="row">
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Vet Name</label>
                                <InputText class="form-control" @bind-Value="newRecord.VetName" />
                            </div>
                            <div class="col-md-6 mb-3">
                                <label class="form-label">Notes</label>
                                <InputText class="form-control" @bind-Value="newRecord.Notes" />
                            </div>
                        </div>
                        <button type="submit" class="btn btn-success">Save Record</button>
                    </EditForm>
                </div>
            </div>
        }

        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Date</th>
                    <th>Diagnosis</th>
                    <th>Treatment</th>
                    <th>Vet</th>
                    <th>Notes</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var record in pet.MedicalRecords)
                {
                    <tr>
                        <td>@record.Date.ToShortDateString()</td>
                        <td>@record.Diagnosis</td>
                        <td>@record.Treatment</td>
                        <td>@record.VetName</td>
                        <td>@record.Notes</td>
                    </tr>
                }
            </tbody>
        </table>
    }

    @if (activeTab == "appointments")
    {
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Date</th>
                    <th>Time</th>
                    <th>Reason</th>
                    <th>Vet</th>
                    <th>Status</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var appt in pet.Appointments)
                {
                    <tr>
                        <td>@appt.ScheduledDate.ToShortDateString()</td>
                        <td>@appt.ScheduledDate.ToShortTimeString()</td>
                        <td>@appt.Reason</td>
                        <td>@appt.VetName</td>
                        <td><span class="badge bg-@GetStatusColor(appt.Status)">@appt.Status</span></td>
                    </tr>
                }
            </tbody>
        </table>
    }

    @if (activeTab == "invoices")
    {
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Date</th>
                    <th>Total</th>
                    <th>Status</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var invoice in pet.Invoices)
                {
                    <tr style="cursor:pointer" @onclick="() => Nav.NavigateTo($&quot;/billing/{invoice.Id}&quot;)">
                        <td>@invoice.IssuedDate.ToShortDateString()</td>
                        <td>@invoice.Items.Sum(i => i.Amount).ToString("C")</td>
                        <td><span class="badge bg-@GetInvoiceStatusColor(invoice.Status)">@invoice.Status</span></td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter] public int Id { get; set; }

    private Pet? pet;
    private string activeTab = "info";
    private bool showMedicalForm;
    private MedicalRecord newRecord = new();

    protected override async Task OnInitializedAsync()
    {
        pet = await ClinicService.GetPetByIdAsync(Id);
    }

    private async Task UpdatePet()
    {
        if (pet != null)
        {
            await ClinicService.UpdatePetAsync(pet);
        }
    }

    private async Task DeletePet()
    {
        await ClinicService.DeletePetAsync(Id);
        Nav.NavigateTo("/patients");
    }

    private void ToggleMedicalForm() => showMedicalForm = !showMedicalForm;

    private async Task CreateMedicalRecord()
    {
        newRecord.PetId = Id;
        newRecord.Date = DateTime.UtcNow;
        await ClinicService.CreateMedicalRecordAsync(newRecord);
        newRecord = new();
        showMedicalForm = false;
        pet = await ClinicService.GetPetByIdAsync(Id);
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "secondary",
        AppointmentStatus.NoShow => "danger",
        _ => "secondary"
    };

    private string GetInvoiceStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Unpaid => "warning",
