                        @foreach (var slot in rescheduleSlots)
                        {
                            <option value="@slot.ToString("HH:mm")">@slot.ToString("HH:mm")</option>
                        }
                    </select>
                </div>
            </div>
            <button class="btn btn-primary" @onclick="ConfirmReschedule" disabled="@(rescheduleTime == null)">Confirm Reschedule</button>
            <button class="btn btn-secondary ms-2" @onclick="CancelReschedule">Cancel</button>
        </div>
    </div>
}

<div class="row">
    @for (var time = selectedDate.Date.AddHours(9); time < selectedDate.Date.AddHours(17); time = time.AddMinutes(30))
    {
        var slotTime = time;
        var appointment = dayAppointments.FirstOrDefault(a => a.ScheduledDate == slotTime);
        var isAvailable = availableSlots.Contains(slotTime);

        <div class="col-md-6 col-lg-4 mb-2">
            @if (appointment != null && appointment.Status == AppointmentStatus.Scheduled)
            {
                <div class="card border-primary">
                    <div class="card-body p-2">
                        <strong>@slotTime.ToString("HH:mm")</strong> - @appointment.Pet?.Name
                        <br /><small class="text-muted">@appointment.Reason - Dr. @appointment.VetName</small>
                        <div class="mt-1">
                            <button class="btn btn-sm btn-outline-warning" @onclick="() => StartReschedule(appointment)">Reschedule</button>
                            <button class="btn btn-sm btn-outline-danger" @onclick="() => CancelAppointment(appointment.Id)">Cancel</button>
                        </div>
                    </div>
                </div>
            }
            else if (isAvailable)
            {
                <div class="card border-success" style="cursor:pointer" @onclick="() => SelectSlot(slotTime)">
                    <div class="card-body p-2 text-success">
                        <strong>@slotTime.ToString("HH:mm")</strong> - Available
                    </div>
                </div>
            }
            else
            {
                <div class="card border-secondary bg-light">
                    <div class="card-body p-2 text-muted">
                        <strong>@slotTime.ToString("HH:mm")</strong> - @(appointment != null ? appointment.Status.ToString() : "Unavailable")
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    private DateTime selectedDate = DateTime.Today;
    private List<Appointment> dayAppointments = new();
    private List<DateTime> availableSlots = new();
    private List<Pet>? allPets;
    private bool showNewAppointmentForm;
    private DateTime? selectedSlot;
    private Appointment newAppointment = new();

    private bool showRescheduleForm;
    private Appointment? rescheduleAppointment;
    private DateTime rescheduleDate = DateTime.Today;
    private List<DateTime> rescheduleSlots = new();
    private DateTime? rescheduleTime;

    protected override async Task OnInitializedAsync()
    {
        allPets = await ClinicService.GetAllPetsAsync();
        await LoadDay();
    }

    private async Task OnDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var date))
        {
            selectedDate = date;
            await LoadDay();
        }
    }

    private async Task LoadDay()
    {
        dayAppointments = await ClinicService.GetAppointmentsByDateAsync(selectedDate);
        availableSlots = await ClinicService.GetAvailableSlotsAsync(selectedDate);
    }

    private void SelectSlot(DateTime slot)
    {
        selectedSlot = slot;
        newAppointment = new Appointment { ScheduledDate = slot };
        showNewAppointmentForm = true;
        showRescheduleForm = false;
    }

    private void CancelForm()
    {
        showNewAppointmentForm = false;
        selectedSlot = null;
    }

    private async Task CreateAppointment()
    {
        if (newAppointment.PetId > 0)
        {
            await ClinicService.CreateAppointmentAsync(newAppointment);
            showNewAppointmentForm = false;
            selectedSlot = null;
            await LoadDay();
        }
    }

    private async Task CancelAppointment(int id)
    {
        await ClinicService.CancelAppointmentAsync(id);
        await LoadDay();
    }

    private async Task StartReschedule(Appointment appt)
    {
        rescheduleAppointment = appt;
        rescheduleDate = DateTime.Today;
        showRescheduleForm = true;
        showNewAppointmentForm = false;
        rescheduleSlots = await ClinicService.GetAvailableSlotsAsync(rescheduleDate);
        rescheduleTime = null;
    }

    private async Task OnRescheduleDateChanged(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var date))
        {
            rescheduleDate = date;
            rescheduleSlots = await ClinicService.GetAvailableSlotsAsync(rescheduleDate);
            rescheduleTime = null;
        }
    }

    private void OnRescheduleTimeChanged(ChangeEventArgs e)
    {
        if (TimeSpan.TryParse(e.Value?.ToString(), out var time))
        {
            rescheduleTime = rescheduleDate.Date.Add(time);
        }
    }

    private async Task ConfirmReschedule()
    {
        if (rescheduleAppointment != null && rescheduleTime != null)
        {
            rescheduleAppointment.ScheduledDate = rescheduleTime.Value;
            await ClinicService.UpdateAppointmentAsync(rescheduleAppointment);
            showRescheduleForm = false;
            rescheduleAppointment = null;
            await LoadDay();
        }
    }

    private void CancelReschedule()
    {
        showRescheduleForm = false;
        rescheduleAppointment = null;
    }
}

