@code {
    private List<Invoice>? invoices;
    private List<Pet>? allPets;
    private string statusFilter = "All";
    private bool showForm;
    private Invoice newInvoice = new();

    private IEnumerable<Invoice> FilteredInvoices => invoices?.Where(i =>
        statusFilter == "All" || i.Status.ToString() == statusFilter
    ) ?? Enumerable.Empty<Invoice>();

    protected override async Task OnInitializedAsync()
    {
        invoices = await ClinicService.GetAllInvoicesAsync();
        allPets = await ClinicService.GetAllPetsAsync();
    }

    private void OnFilterChanged(ChangeEventArgs e)
    {
        statusFilter = e.Value?.ToString() ?? "All";
    }

