    {
        if (newInvoice.PetId > 0)
        {
            newInvoice.IssuedDate = DateTime.UtcNow;
            await ClinicService.CreateInvoiceAsync(newInvoice);
            newInvoice = new();
            showForm = false;
            invoices = await ClinicService.GetAllInvoicesAsync();
        }
    }

    private string GetStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Unpaid => "warning",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.Overdue => "danger",
        InvoiceStatus.Cancelled => "secondary",
        _ => "secondary"
    };
}

